command:example.dev:code:
$rows = @(
                [pscustomobject]@{ Region = 'North America'; Product = 'Standard'; Sales = 125000 }
                [pscustomobject]@{ Region = 'EMEA'; Product = 'Standard'; Sales = 98000 }
                [pscustomobject]@{ Region = 'APAC'; Product = 'Premium'; Sales = 143000 }
            )
            New-OfficeExcel -Path .\SalesPivot.xlsx {
                Add-OfficeExcelSheet -Name Data {
                    Add-OfficeExcelTable -Data $rows -TableName Sales -AutoFit
                    Add-OfficeExcelPivotTable -SourceRange 'A1:C4' -DestinationCell 'E2' -Name 'SalesByRegion' -RowField Region -ColumnField Product -DataField Sales -DataFunction Sum -PivotStyle PivotStyleMedium9
                }
            }

New-OfficeExcel -Path .\Operations.xlsx {
                Add-OfficeExcelReportSheet -Name Summary {
                    Add-OfficeExcelReportCallout -Kind Warning -Title 'Manual validation' -Body 'Open the workbook in desktop Excel before publishing pivot-heavy reports.'
                }
            }

New-OfficeExcel -Path .\Operations.xlsx {
                Add-OfficeExcelReportSheet -Name Summary {
                    Add-OfficeExcelReportKpiRow -Data @{ Revenue = 125000; Incidents = 3; Status = 'Ready' } -PerRow 3
                }
            }

$legendRows = @(
                [pscustomobject]@{ Status = 'Ready'; Meaning = 'Validated and ready' }
                [pscustomobject]@{ Status = 'Review'; Meaning = 'Needs owner review' }
            )
            New-OfficeExcel -Path .\Operations.xlsx {
                Add-OfficeExcelReportSheet -Name Summary {
                    Add-OfficeExcelReportLegend -Title 'Status legend' -Headers Status, Meaning -Rows $legendRows -FirstColumnFillByValue @{ Ready = '#d9f7be'; Review = '#fff7e6' }
                }
            }

New-OfficeExcel -Path .\Operations.xlsx {
                Add-OfficeExcelReportSheet -Name Summary {
                    Add-OfficeExcelReportTitle -Title 'Operational Summary'
                    Add-OfficeExcelReportParagraph -Text 'This workbook was generated from the validated source data.'
                }
            }

New-OfficeExcel -Path .\Operations.xlsx {
                Add-OfficeExcelReportSheet -Name Summary {
                    Add-OfficeExcelReportSection -Text 'Service health'
                    Add-OfficeExcelReportParagraph -Text 'All monitored services are reporting.'
                }
            }

New-OfficeExcel -Path .\report.xlsx {
                Add-OfficeExcelReportSheet -Name Summary {
                  Add-OfficeExcelReportTitle -Title 'Operational Summary' -Subtitle 'Current view'
                  Add-OfficeExcelReportKpiRow -Data @{ Ready = 12; Blocked = 2 }
                }
              }

New-OfficeExcel -Path .\Operations.xlsx {
                Add-OfficeExcelReportSheet -Name Summary {
                    Add-OfficeExcelReportTitle -Title 'Operational Summary'
                    Add-OfficeExcelReportSpacer -Rows 2
                    Add-OfficeExcelReportSection -Text 'Details'
                }
            }

$rows = @(
                [pscustomobject]@{ Area = 'PDF'; Status = 'Ready' }
                [pscustomobject]@{ Area = 'Word'; Status = 'Review' }
            )
            New-OfficeExcel -Path .\Operations.xlsx {
                Add-OfficeExcelReportSheet -Name Summary {
                    Add-OfficeExcelReportTable -Data $rows -Title 'Documentation coverage' -TableStyle TableStyleMedium9
                }
            }

New-OfficeExcel -Path .\Operations.xlsx {
                Add-OfficeExcelReportSheet -Name Summary {
                    Add-OfficeExcelReportTitle -Title 'Operational Summary' -Subtitle 'Current month'
                    Add-OfficeExcelReportKpiRow -Data @{ Revenue = 125000; Incidents = 3; Status = 'Ready' }
                }
            }

New-OfficeMarkdown -Path .\ReleaseNotes.md {
                Add-OfficeMarkdownHeading -Level 1 -Text 'Release notes'
                Add-OfficeMarkdownCallout -Kind 'note' -Title 'Validation' -Body 'Artifacts were generated from deterministic example data.'
                Add-OfficeMarkdownCallout -Kind 'warning' -Title 'Manual step' -Body 'Open the workbook in desktop Excel before publishing pivots.'
            }

New-OfficeMarkdown -Path .\Report.md {
                Add-OfficeMarkdownHeading -Level 1 -Text 'Operational Report'
                Add-OfficeMarkdownTableOfContents -Title 'Contents' -MinLevel 2 -MaxLevel 3 -PlaceAtTop
                Add-OfficeMarkdownHeading -Level 2 -Text 'Overview'
                Add-OfficeMarkdownParagraph -Text 'Current operational state.'
            }

New-OfficeMarkdown -Path .\Report.md {
                Add-OfficeMarkdownHeading -Level 2 -Text 'Summary'
                Add-OfficeMarkdownParagraph -Text 'Key decisions and status.'
                Add-OfficeMarkdownHorizontalRule
                Add-OfficeMarkdownHeading -Level 2 -Text 'Appendix'
            }

New-OfficeMarkdown -Path .\Plan.md {
                Add-OfficeMarkdownHeading -Level 2 -Text 'Priorities'
                Add-OfficeMarkdownList -Items 'PDF examples', 'PowerPoint layout', 'Word report polish'
                Add-OfficeMarkdownHeading -Level 2 -Text 'Release order'
                Add-OfficeMarkdownList -Items 'Validate artifacts', 'Generate docs', 'Publish release' -Ordered -Start 1
            }

New-OfficeMarkdown -Path .\Report.md {
                Add-OfficeMarkdownHeading -Level 1 -Text 'Operational Report'
                Add-OfficeMarkdownParagraph -Text 'This report is generated automatically from validated source data.'
                Add-OfficeMarkdownParagraph -Text 'Use the linked artifacts for workbook, PDF, and presentation proof.'
            }

New-OfficeMarkdown -Path .\ExecutiveSummary.md {
                Add-OfficeMarkdownHeading -Level 1 -Text 'Executive summary'
                Add-OfficeMarkdownQuote -Text 'The release is ready when examples, generated docs, and artifact readback all agree.'
                Add-OfficeMarkdownParagraph -Text 'Detailed validation follows.'
            }

New-OfficeMarkdown -Path .\ReleaseChecklist.md {
                Add-OfficeMarkdownHeading -Level 1 -Text 'Release checklist'
                Add-OfficeMarkdownTaskList -Items 'Generate examples', 'Refresh docs', 'Validate artifacts', 'Publish release' -Completed 0, 1
            }

$dataPath = '.\Examples\Documents\ServiceData.json'
            Set-Content -Path $dataPath -Value '{ "service": "Directory", "status": "Healthy" }'
            New-OfficePdf -Path .\Examples\Documents\PdfWithAttachment.pdf {
                Add-OfficePdfHeading -Text 'Service report'
                Add-OfficePdfAttachment -Path $dataPath -Name 'service-data.json' -MimeType 'application/json' -Description 'Source data used by the report.'
            }

New-OfficePdf -Path .\Report.pdf {
                PdfBackgroundShape -Shape TopBand -Height 86 -FillColor '#DBEAFE' -FillOpacity 0.75
                PdfBackgroundShape -Shape Ellipse -X 420 -Y 650 -Width 96 -Height 72 -FillColor '#99F6E4' -FillOpacity 0.35
                PdfHeading 'Styled report'
              }

New-OfficePdf -Path .\Examples\Documents\PdfBookmarks.pdf {
                Add-OfficePdfText -Run @(
                  @{ Text = 'Jump to details'; LinkDestinationName = 'details'; Color = '#2563EB'; Underline = $true }
                )
                Add-OfficePdfPageBreak
                Add-OfficePdfBookmark -Name 'details'
                Add-OfficePdfHeading -Text 'Details' -Level 2
              }

New-OfficePdf -Path .\Examples\Documents\PdfHeadings.pdf {
                Add-OfficePdfHeading -Text 'Service Review' -Level 1 -Color '#1D4ED8'
                Add-OfficePdfHeading -Text 'Open risks' -Level 2
                Add-OfficePdfParagraph -Text 'Heading levels create the report structure.'
              }

New-OfficePdf -Path .\Examples\Documents\PdfDivider.pdf {
                Add-OfficePdfHeading -Text 'Executive summary'
                Add-OfficePdfParagraph -Text 'The service is healthy.'
                Add-OfficePdfHorizontalRule -Color '#CBD5E1' -Thickness 0.75 -SpacingBefore 10 -SpacingAfter 10
                Add-OfficePdfHeading -Text 'Signals' -Level 2
              }

$image = '.\Tests\Assets\CellImage.png'
            New-OfficePdf -Path .\Examples\Documents\PdfImage.pdf {
                Add-OfficePdfHeading -Text 'Visual evidence'
                Add-OfficePdfImage -Path $image -Width 120 -Height 80 -Align Center -AlternativeText 'Sample chart image'
            }

New-OfficePdf -Path .\Examples\Documents\PdfList.pdf {
                Add-OfficePdfHeading -Text 'Next actions'
                Add-OfficePdfList -Items 'Confirm owner','Publish summary','Schedule review' -Numbered
            }

New-OfficePdf -Path .\Examples\Documents\PdfPageBreak.pdf {
                Add-OfficePdfHeading -Text 'Service review'
                Add-OfficePdfParagraph -Text 'Summary content stays on the first page.'
                Add-OfficePdfPageBreak
                Add-OfficePdfHeading -Text 'Appendix' -Level 2
            }

New-OfficePdf -Path .\Examples\Documents\PdfPanel.pdf {
                Add-OfficePdfHeading -Text 'Executive summary'
                Add-OfficePdfPanel -Text 'No critical incidents were detected in the current reporting window.' -Align Center
            }

New-OfficePdf -Path .\Examples\Documents\PdfParagraph.pdf {
                Add-OfficePdfHeading -Text 'Status'
                Add-OfficePdfParagraph -Text 'All monitored services are currently healthy.' -Color '#166534'
            }

New-OfficePdf -Path .\Report.pdf {
                PdfRow -Gap 16 -Column @(
                  @{ Width = 35; Content = @(
                    @{ Type = 'Heading'; Level = 2; Text = 'Signals' }
                    @{ Type = 'List'; Items = @('Healthy', 'Watch', 'Needs action') }
                  ) }
                  @{ Width = 65; Content = @(
                    @{ Type = 'Panel'; Text = 'Right-side callout content.' }
                  ) }
                )
              }

New-OfficePdf -Path .\Report.pdf {
                PdfBookmark 'details'
                PdfRow -Column @(
                  @{ Content = @(
                    @{ Type = 'Paragraph'; Run = @(
                      @{ Text = 'Jump to ' }
                      @{ Text = 'details'; LinkDestinationName = 'details'; Color = '#7C3AED' }
                    ) }
                  ) }
                )
              }

New-OfficePdf -Path .\Examples\Documents\PdfSpacer.pdf {
                Add-OfficePdfHeading -Text 'Summary'
                Add-OfficePdfParagraph -Text 'First block.'
                Add-OfficePdfSpacer -Height 18
                Add-OfficePdfParagraph -Text 'Second block after additional spacing.'
            }

$services = @(
                [pscustomobject]@{ Name = 'Directory'; Status = 'Healthy'; Incidents = 0 }
                [pscustomobject]@{ Name = 'Mail'; Status = 'Watch'; Incidents = 2 }
            )
            New-OfficePdf -Path .\Examples\Documents\PdfTable.pdf {
                Add-OfficePdfHeading -Text 'Service status'
                Add-OfficePdfTable -InputObject $services -Property Name,Status,Incidents -Header 'Service','Status','Incidents'
            }

New-OfficePdf -Path .\Report.pdf {
                PdfBookmark 'summary'
                PdfText -Run @(
                  @{ Text = 'Read the ' }
                  @{ Text = 'website'; LinkUri = 'https://evotec.xyz'; Color = '#2563EB' }
                  @{ Text = ' or jump to ' }
                  @{ Text = 'summary'; LinkDestinationName = 'summary'; Color = '#7C3AED' }
                  @{ Text = '.' }
                )
              }

New-OfficePdf -Path .\Examples\Documents\PdfWatermark.pdf {
                Add-OfficePdfWatermark -Text 'DRAFT' -FontSize 72 -Opacity 0.12 -RotationAngle -35 -Color '#64748B'
                Add-OfficePdfHeading -Text 'Draft service review'
                Add-OfficePdfParagraph -Text 'This copy is not final.'
            }

New-OfficePowerPoint -Path .\Examples\Documents\PowerPointBullets.pptx {
                $slide = Add-OfficePowerPointSlide -Layout 1
                Set-OfficePowerPointSlideTitle -Slide $slide -Title 'Delivery update'
                Add-OfficePowerPointBullets -Slide $slide -Bullets 'Wins','Risks','Next steps' -X 60 -Y 120 -Width 420 -Height 180
            }

$rows = @(
                [pscustomobject]@{ Month = 'Jan'; Sales = 42; Profit = 9 }
                [pscustomobject]@{ Month = 'Feb'; Sales = 55; Profit = 13 }
            )
            New-OfficePowerPoint -Path .\Examples\Documents\PowerPointChart.pptx {
                $slide = Add-OfficePowerPointSlide -Layout 1
                Add-OfficePowerPointChart -Slide $slide -Data $rows -CategoryProperty Month -SeriesProperty Sales,Profit -Title 'Monthly performance'
            }

$rows = @(
                [pscustomobject]@{ Quarter = 1; Revenue = 20 }
                [pscustomobject]@{ Quarter = 2; Revenue = 34 }
            )
            New-OfficePowerPoint -Path .\Examples\Documents\PowerPointScatter.pptx {
                $slide = Add-OfficePowerPointSlide -Layout 1
                Add-OfficePowerPointChart -Slide $slide -Type Scatter -Data $rows -XProperty Quarter -YProperty Revenue -Title 'Revenue trend'
            }

$plan = New-OfficePowerPointDeckPlan {
                Add-OfficePowerPointPlanSection -Title 'Service Review'
                Add-OfficePowerPointPlanCardGrid -Title 'Current signals' -Cards @(
                  @{ Title = 'Availability'; Items = @('Healthy', 'No critical incidents') }
                  @{ Title = 'Risk'; Items = @('One dependency on watch') }
                )
            }
            New-OfficePowerPoint -Path .\Examples\Documents\DesignerDeck.pptx {
                Add-OfficePowerPointDesignerDeck -Plan $plan -AccentColor '#0F766E' -Purpose 'monthly service brief'
            }

$sections = @(
                @{ Heading = 'Monitoring'; Body = 'Signals and ownership'; Items = @('Alerts', 'Dashboards') }
                @{ Heading = 'Reporting'; Body = 'Executive-ready output'; Items = @('Summary', 'Appendix') }
            )
            New-OfficePowerPointDeckPlan {
                Add-OfficePowerPointPlanCapability -Title 'Capabilities' -Subtitle 'What the team provides' -Sections $sections
            }

$cards = @(
                @{ Title = 'Availability'; Items = @('99.98%', 'No major incidents'); AccentColor = '#16A34A' }
                @{ Title = 'Risk'; Items = @('One dependency on watch'); AccentColor = '#F59E0B' }
            )
            New-OfficePowerPointDeckPlan {
                Add-OfficePowerPointPlanCardGrid -Title 'Current signals' -Cards $cards
            }

$sections = @(
                @{ Heading = 'Challenge'; Body = 'Manual reports took too long to produce.' }
                @{ Heading = 'Outcome'; Body = 'Automated generation made the review repeatable.' }
            )
            $metrics = @(
                @{ Value = '4h'; Label = 'saved each cycle' }
                @{ Value = '0'; Label = 'manual copy steps' }
            )
            New-OfficePowerPointDeckPlan {
                Add-OfficePowerPointPlanCaseStudy -Title 'Automation impact' -Sections $sections -Metrics $metrics
            }

$locations = @(
                @{ Name = 'EMEA'; X = 0.45; Y = 0.35; Detail = 'Primary operations' }
                @{ Name = 'AMER'; X = 0.22; Y = 0.42; Detail = 'Support window' }
            )
            New-OfficePowerPointDeckPlan {
                Add-OfficePowerPointPlanCoverage -Title 'Regional coverage' -Subtitle 'Operational footprint' -Locations $locations
            }

$logos = @(
                @{ Name = 'Directory'; Subtitle = 'Identity platform'; AccentColor = '#2563EB' }
                @{ Name = 'Mail'; Subtitle = 'Messaging platform'; AccentColor = '#0F766E' }
            )
            New-OfficePowerPointDeckPlan {
                Add-OfficePowerPointPlanLogoWall -Title 'Systems covered' -Subtitle 'Representative services' -Logos $logos
            }

$steps = @(
                @{ Title = 'Collect'; Body = 'Gather health and delivery signals' }
                @{ Title = 'Review'; Body = 'Confirm decisions with owners' }
                @{ Title = 'Publish'; Body = 'Send the service brief' }
            )
            New-OfficePowerPointDeckPlan {
                Add-OfficePowerPointPlanProcess -Title 'Operating rhythm' -Subtitle 'How the review is produced' -Steps $steps
            }

$plan = New-OfficePowerPointDeckPlan {
                Add-OfficePowerPointPlanSection -Title 'Service Review' -Subtitle 'Monthly operating brief' -Seed 'service-review'
                Add-OfficePowerPointPlanCardGrid -Title 'Signals' -Cards @(
                  @{ Title = 'Health'; Items = @('Green', 'No blockers') }
                )
            }

New-OfficePowerPoint -Path .\Examples\Documents\PowerPointSections.pptx {
                Add-OfficePowerPointSlide -Layout 1 | Set-OfficePowerPointSlideTitle -Title 'Overview'
                Add-OfficePowerPointSlide -Layout 1 | Set-OfficePowerPointSlideTitle -Title 'Results'
                Add-OfficePowerPointSection -Name 'Results' -StartSlideIndex 1
            }

New-OfficePowerPoint -Path .\Examples\Documents\PowerPointShape.pptx {
                $slide = Add-OfficePowerPointSlide -Layout 1
                Add-OfficePowerPointShape -Slide $slide -ShapeType Rectangle -X 60 -Y 120 -Width 220 -Height 90 -FillColor '#DDEEFF' -OutlineColor '#2563EB' -OutlineWidth 1
                Add-OfficePowerPointTextBox -Slide $slide -Text 'Highlighted status' -X 80 -Y 145 -Width 180 -Height 32
            }

New-OfficePowerPoint -Path .\Examples\Documents\PowerPointTextBox.pptx {
                $slide = Add-OfficePowerPointSlide -Layout 1
                Add-OfficePowerPointTextBox -Slide $slide -Text 'Quarterly overview' -X 80 -Y 150 -Width 320 -Height 50
                Add-OfficePowerPointTextBox -Slide $slide -Text 'Generated by PSWriteOffice' -X 80 -Y 210 -Width 320 -Height 35
            }

$rows = @(
                [pscustomobject]@{ Region = 'North America'; Revenue = 125000; Profit = 42000 }
                [pscustomobject]@{ Region = 'EMEA'; Revenue = 98000; Profit = 31000 }
                [pscustomobject]@{ Region = 'APAC'; Revenue = 143000; Profit = 52000 }
            )
            New-OfficeWord -Path .\RegionalReport.docx {
                Add-OfficeWordParagraph -Text 'Regional revenue'
                Add-OfficeWordChart -Type Pie -Data $rows -CategoryProperty Region -SeriesProperty Revenue -Title 'Revenue mix' -FitToPageWidth -WidthFraction 0.75
                Add-OfficeWordChart -Type Bar -Data $rows -CategoryProperty Region -SeriesProperty Revenue, Profit -Legend -XAxisTitle 'Region' -YAxisTitle 'Amount'
            }

$trend = @(
                [pscustomobject]@{ Month = 'Jan'; Sales = 10; Profit = 4 }
                [pscustomobject]@{ Month = 'Feb'; Sales = 12; Profit = 5 }
                [pscustomobject]@{ Month = 'Mar'; Sales = 15; Profit = 7 }
            )
            $doc = New-OfficeWord -Path .\Trend.docx -PassThru
            Add-OfficeWordChart -Document $doc -Type Line -Data $trend -CategoryProperty Month -SeriesProperty Sales, Profit -Legend -Title 'Quarter trend'
            Save-OfficeWord -Document $doc

$omml = '<m:oMath xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><m:r><m:t>x+1</m:t></m:r></m:oMath>'
            New-OfficeWord -Path .\Formula.docx {
                Add-OfficeWordParagraph -Text 'The following expression is stored as Office Math.'
                Add-OfficeWordEquation -Omml $omml
            }

New-OfficeWord -Path .\StatusReport.docx {
                Add-OfficeWordParagraph -Text 'Release readiness'
                Add-OfficeWordShape -Type Rectangle -Width 220 -Height 56 -FillColor '#e6fffb' -StrokeColor '#08979c' -StrokeWidth 1.5 -Title 'Status callout' -Description 'Release readiness callout'
            }

$pdf = New-OfficePdf {
                Add-OfficePdfBackgroundShape -Shape Rectangle -FillColor '#EEF2FF' -X 0 -Y 0 -Width 595 -Height 120
                Add-OfficePdfHeading -Text 'Clean variant'
            } -NoSave
            $pdf | Clear-OfficePdfBackgroundShape -PassThru | Save-OfficePdf -Path .\Examples\Documents\PdfNoBackgroundShape.pdf

New-OfficeExcel -Path .\report.xlsx {
                Add-OfficeExcelSheet -Name Data {
                    Set-OfficeExcelRow -Row 1 -Values 'Region', 'Revenue'
                    Set-OfficeExcelRow -Row 2 -Values 'EMEA', 98000
                }
            }
            $workbook = Get-OfficeExcel -Path .\report.xlsx
            $workbook | Close-OfficeExcel -Save -Path .\report-final.xlsx -SafePreflight -ValidateOpenXml

$differences = Compare-OfficeExcelRange -Path .\Report.xlsx -LeftSheet Current -RightSheet Expected -LeftRange A1:D20 -RightRange A1:D20 -TrimStrings -IgnoreCase
            if ($differences) {
                $differences | Export-Csv -Path .\RangeDifferences.csv -NoTypeInformation
            }

$rows = @(
                [ordered]@{ Id = 1; Name = 'Alpha'; Total = 10.5 },
                [ordered]@{ Id = 2; Name = 'Beta'; Total = 7.25 }
              )
              $rows | ConvertTo-OfficeCsv -OutputPath .\export.csv -Delimiter ';'

New-OfficePowerPoint -Path .\Examples\Documents\PowerPointCopySlide.pptx {
                $slide = Add-OfficePowerPointSlide -Layout 1
                Set-OfficePowerPointSlideTitle -Slide $slide -Title 'Original'
                $copy = Copy-OfficePowerPointSlide -Index 0
                Set-OfficePowerPointSlideTitle -Slide $copy -Title 'Copied appendix'
            }

$pdf = New-OfficePdf {
                Set-OfficePdfCompliance -Profile PdfA3B -Groundwork
                Add-OfficePdfHeading -Text 'Compliance readiness'
            } -NoSave
            $pdf | Get-OfficePdfCompliance -Profile PdfA3B

Get-OfficePdfFormField -Path .\Examples\Documents\Request.pdf |
                Select-Object Name, FieldType, Value
            Set-OfficePdfForm -Path .\Examples\Documents\Request.pdf -OutputPath .\Examples\Documents\Request-Filled.pdf -Field @{ Requester = 'Ada Lovelace' }

New-OfficePowerPoint -Path .\Examples\Documents\PowerPointLayoutBox.pptx {
                $slide = Add-OfficePowerPointSlide -Layout 1
                $box = Get-OfficePowerPointLayoutBox -MarginCm 1.5
                Add-OfficePowerPointTextBox -Slide $slide -Text 'Inside the content box' -X ($box.LeftPoints) -Y ($box.TopPoints) -Width ($box.WidthPoints) -Height 60
            }

New-OfficePowerPoint -Path .\Examples\Documents\PowerPointColumns.pptx {
                $slide = Add-OfficePowerPointSlide -Layout 1
                $columns = Get-OfficePowerPointLayoutBox -ColumnCount 2 -MarginCm 1.5 -GutterCm 1.0
                Add-OfficePowerPointTextBox -Slide $slide -Text 'Left column' -X ($columns[0].LeftPoints) -Y ($columns[0].TopPoints) -Width ($columns[0].WidthPoints) -Height 80
                Add-OfficePowerPointTextBox -Slide $slide -Text 'Right column' -X ($columns[1].LeftPoints) -Y ($columns[1].TopPoints) -Width ($columns[1].WidthPoints) -Height 80
            }

New-OfficePdf -Path .\ServiceReview.pdf {
                PdfTheme Report
                PdfMetadata -Title 'Service Review' -Author 'PSWriteOffice'
                PdfPageSetup -PageSize A4 -Margin 42
                PdfHeader 'Service Review'
                PdfFooter 'Page {page}/{pages}'
                PdfHeading 'Service Review'
                PdfText -Run @(
                  @{ Text = 'Generated with ' }
                  @{ Text = 'rich inline text'; Bold = $true; Color = '#0F766E' }
                  @{ Text = ' and OfficeIMO.Pdf layout.' }
                )
                PdfRow -Column @(
                  @{ Width = 40; Content = @(@{ Type = 'Panel'; Text = 'Left summary' }) }
                  @{ Width = 60; Content = @(@{ Type = 'Paragraph'; Text = 'Right details' }) }
                )
              }

$plan = New-OfficePowerPointDeckPlan {
                Add-OfficePowerPointPlanSection -Title 'Service Review' -Subtitle 'Monthly operating brief'
                Add-OfficePowerPointPlanProcess -Title 'Operating rhythm' -Steps @(
                  @{ Title = 'Collect'; Body = 'Gather health signals' }
                  @{ Title = 'Review'; Body = 'Confirm owner decisions' }
                  @{ Title = 'Publish'; Body = 'Share the final brief' }
                )
            }
            New-OfficePowerPoint -Path .\Examples\Documents\DesignerDeck.pptx {
                Add-OfficePowerPointDesignerDeck -Plan $plan
            }

ExcelSheet 'Data' {
                Set-OfficeExcelColumnStyleByHeader -Header Revenue -Style Currency -CultureName en-US -AutoFit
                Set-OfficeExcelColumnStyleByHeader -Header Status -BackgroundByText @{ Ready = '#D4EDDA'; Blocked = '#F8D7DA' } -BoldByText Blocked
              }

New-OfficePdf -Path .\Examples\Documents\PdfBackground.pdf {
                Set-OfficePdfBackground -Color '#F8FAFC'
                Add-OfficePdfHeading -Text 'Report on a soft background'
                Add-OfficePdfParagraph -Text 'The background color applies to generated pages.'
            }

New-OfficePdf -Path .\Examples\Documents\PdfCompliance.pdf {
                Set-OfficePdfCompliance -Profile PdfA3B -Groundwork -Language 'en-US'
                Add-OfficePdfHeading -Text 'Compliance-ready report'
                Get-OfficePdfCompliance -Profile PdfA3B
            }

New-OfficePdf -Path .\Examples\Documents\PdfFooter.pdf {
                Set-OfficePdfFooter -Text 'Page {page} of {pages}' -Align Center -FontSize 8
                Add-OfficePdfHeading -Text 'Report with footer'
                Add-OfficePdfPageBreak
                Add-OfficePdfParagraph -Text 'The footer includes generated page numbers.'
            }

New-OfficePdf -Path .\Examples\Documents\PdfHeader.pdf {
                Set-OfficePdfHeader -Text 'Service Review' -Align Right -FontSize 9
                Add-OfficePdfHeading -Text 'Service Review'
                Add-OfficePdfParagraph -Text 'The header repeats on generated pages.'
            }

New-OfficePdf -Path .\Examples\Documents\PdfPageSetup.pdf {
                Set-OfficePdfPageSetup -PageSize A4 -Margin 42
                Add-OfficePdfHeading -Text 'A4 report'
                Add-OfficePdfParagraph -Text 'The report uses custom margins.'
            }

New-OfficePdf -Path .\Report.pdf {
                PdfTheme Report
                PdfHeading 'Service Review'
                PdfParagraph 'The report theme defines a polished baseline.'
              }

New-OfficePowerPoint -Path .\Examples\Documents\PowerPointNotes.pptx {
                $slide = Add-OfficePowerPointSlide -Layout 1
                Set-OfficePowerPointSlideTitle -Slide $slide -Title 'Executive summary'
                Set-OfficePowerPointNotes -Slide $slide -Text 'Keep this slide under five minutes and focus on decisions.'
            }

New-OfficePowerPoint -Path .\Examples\Documents\PowerPointPlaceholderText.pptx {
                $slide = Add-OfficePowerPointSlide -Layout 1
                Set-OfficePowerPointPlaceholderText -Slide $slide -PlaceholderType Title -Text 'Agenda'
                Set-OfficePowerPointPlaceholderText -Slide $slide -PlaceholderType Body -Text 'Review signals and decisions' -IgnoreMissing
            }

New-OfficePowerPoint -Path .\Examples\Documents\PowerPointWidescreen.pptx {
                Set-OfficePowerPointSlideSize -Preset Screen16x9
                Add-OfficePowerPointSlide -Layout 1 | Set-OfficePowerPointSlideTitle -Title 'Widescreen deck'
            }

New-OfficePowerPoint -Path .\Examples\Documents\PowerPointThemeFonts.pptx {
                Set-OfficePowerPointThemeFonts -MajorLatin 'Aptos Display' -MinorLatin 'Aptos' -AllMasters
                Add-OfficePowerPointSlide -Layout 1 | Set-OfficePowerPointSlideTitle -Title 'Theme fonts'
            }

New-OfficePowerPoint -Path .\Examples\Documents\PowerPointThemeName.pptx {
                Set-OfficePowerPointThemeName -Name 'Service Brief' -AllMasters
                Add-OfficePowerPointSlide -Layout 1 | Set-OfficePowerPointSlideTitle -Title 'Named theme'
            }

New-OfficeWord -Path .\QuarterlyReport.docx {
                Set-OfficeWordDocumentProperty -Name Title -Value 'Quarterly Report'
                Set-OfficeWordDocumentProperty -Name ReleaseStatus -Value 'Approved' -Custom
                Add-OfficeWordParagraph -Text 'Approved quarterly report'
            }
            Get-OfficeWordDocumentProperty -Path .\QuarterlyReport.docx -Name Title, ReleaseStatus

New-OfficeWord -Path .\Report.docx {
                Add-OfficeWordTableOfContent
                Set-OfficeWordTableOfContent -Text 'Contents' -TextNoContent 'No entries yet'
                Add-OfficeWordParagraph -Text 'Executive summary' -Style Heading1
                Update-OfficeWordTableOfContent
            }

$count = Update-OfficeExcelText -Path .\Report.xlsx -Sheet Summary -OldValue Draft -NewValue Ready
            [pscustomobject]@{
                Path = '.\Report.xlsx'
                Replacements = $count
            }

New-OfficeWord -Path .\ExecutiveReport.docx {
                Add-OfficeWordTableOfContent
                Add-OfficeWordParagraph -Text 'Executive summary' -Style Heading1
                Add-OfficeWordParagraph -Text 'Summary text'
                Update-OfficeWordTableOfContent
            }
